import React, { useEffect, useState } from 'react';
import axios from 'axios';

export default function AdminPasses() {
  const [passes, setPasses] = useState([]);
  const [filter, setFilter] = useState('');
  const [loading, setLoading] = useState(false);

  const load = (status = '') => {
    setFilter(status);
    const url = status ? `/api/admin/passes?status=${status}` : '/api/admin/passes';
    axios.get(url).then(r => setPasses(r.data));
  };

  useEffect(() => load(), []);

  const approve = async (id) => {
    setLoading(true);
    await axios.put(`/api/admin/passes/${id}/approve`, {});
    load(filter); setLoading(false);
  };

  const reject = async (id) => {
    const reason = prompt('Rejection reason (optional):') || 'Not eligible';
    await axios.put(`/api/admin/passes/${id}/reject`, { remarks: reason });
    load(filter);
  };

  const statuses = ['', 'pending', 'approved', 'rejected', 'expired'];

  return (
    <div className="page-container animate-fade-in">
      <h1 className="page-title" style={{ textAlign: 'left', marginBottom: '24px' }}>📋 Manage Bus Passes</h1>

      <div style={{ display: 'flex', gap: '10px', marginBottom: '24px', flexWrap: 'wrap' }}>
        {statuses.map(st => (
          <button 
            key={st} 
            className={filter === st ? 'btn btn-primary btn-small' : 'btn btn-outline btn-small'}
            onClick={() => load(st)}
            style={{ borderRadius: '20px' }}
          >
            {st ? st.charAt(0).toUpperCase() + st.slice(1) : 'All'}
          </button>
        ))}
      </div>

      <div className="table-container">
        <table className="glass-table">
          <thead>
            <tr>
              <th>Student</th>
              <th>USN</th>
              <th>Route</th>
              <th>Type / Payment</th>
              <th>Applied</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {passes.map(p => (
              <tr key={p._id}>
                <td>
                  <div style={{ fontWeight: 600, color: 'var(--text-dark)' }}>{p.student?.name}</div>
                  <div style={{ color: 'var(--text-light)', fontSize: 12 }}>{p.student?.email}</div>
                </td>
                <td>{p.usn}</td>
                <td>{p.from} → {p.to}</td>
                <td>
                  <div style={{ textTransform: 'capitalize' }}>{p.passType}</div>
                  {p.paymentStatus && <div style={{ fontSize: 12, color: p.paymentStatus === 'completed' ? 'var(--success)' : 'var(--warning)' }}>{p.paymentStatus}</div>}
                </td>
                <td>{new Date(p.appliedAt).toLocaleDateString()}</td>
                <td><span className={`badge badge-${p.status}`}>{p.status}</span></td>
                <td>
                  {p.status === 'pending' && (
                    <div style={{ display: 'flex', gap: '8px' }}>
                      <button className="btn btn-success btn-small" onClick={() => approve(p._id)} disabled={loading}>✓</button>
                      <button className="btn btn-danger btn-small" onClick={() => reject(p._id)} disabled={loading}>✗</button>
                    </div>
                  )}
                  {p.status !== 'pending' && <span style={{ color: '#ccc', fontSize: 12 }}>—</span>}
                </td>
              </tr>
            ))}
            {passes.length === 0 && (
              <tr><td colSpan={7} style={{ textAlign: 'center', color: 'var(--text-light)', padding: 30 }}>No passes found</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
